65	/// Concurrent intern table for atom strings.
66	///
67	/// The table stores atoms in both directions. Strings are leaked when first
68	/// interned because runtime atoms are never freed in this design, which lets
69	/// `resolve` return a borrowed `&str` without tying it to a map guard.
70	pub struct AtomTable {
71	    by_name: DashMap<&'static str, Atom>,
72	    by_index: DashMap<u32, &'static str>,
73	    next_index: AtomicU32,
74	}
75	
76	impl AtomTable {
77	    /// Create an empty atom table.
78	    #[must_use]
79	    pub fn new() -> Self {
80	        Self {
81	            by_name: DashMap::new(),
82	            by_index: DashMap::new(),
83	            next_index: AtomicU32::new(0),
84	        }
85	    }
86	
87	    /// Create an atom table with the common atoms at stable indices.
88	    #[must_use]
89	    pub fn with_common_atoms() -> Self {
90	        let table = Self::new();
91	
92	        for &(name, atom) in COMMON_ATOMS {
93	            table.by_name.insert(name, atom);
94	            table.by_index.insert(atom.index(), name);
95	        }
96	
97	        table
98	            .next_index
99	            .store(COMMON_ATOMS.len() as u32, Ordering::Relaxed);
100	        table
101	    }
102	
103	    /// Intern `name`, returning its existing or newly assigned atom.
104	    pub fn intern(&self, name: &str) -> Atom {
105	        if let Some(atom) = self.by_name.get(name).map(|entry| *entry) {
106	            return atom;
107	        }
108	
109	        let leaked_name: &'static str = Box::leak(name.to_owned().into_boxed_str());
110	
111	        match self.by_name.entry(leaked_name) {
112	            Entry::Occupied(entry) => *entry.get(),
113	            Entry::Vacant(entry) => {
114	                let index = self.next_index.fetch_add(1, Ordering::Relaxed);
115	                let atom = Atom::new(index);
116	                self.by_index.insert(index, leaked_name);
117	                entry.insert(atom);
118	                atom
119	            }
120	        }
121	    }
122	
123	    /// Resolve an atom back to its original string.
124	    #[must_use]
125	    pub fn resolve(&self, atom: Atom) -> Option<&str> {
126	        self.by_index.get(&atom.index()).map(|entry| *entry)
127	    }
128	}
